import sys
from functools import lru_cache
input = sys.stdin.readline

def solve():
    N = int(input())
    A = list(map(int, input().split()))

    @lru_cache(maxsize=None)
    def wins(l, r, last):
        # Current player wins?
        if l > r:
            return False
        can_left = A[l] > last
        can_right = A[r] > last
        if not can_left and not can_right:
            return False
        if can_left and not wins(l+1, r, A[l]):
            return True
        if can_right and not wins(l, r-1, A[r]):
            return True
        return False

    print("Alice" if wins(0, N-1, -1) else "Bob")

solve()

