import sys
from functools import lru_cache

def solve():
    input_data = sys.stdin.read().split()
    n = int(input_data[0])
    A = list(map(int, input_data[1:n+1]))

    # Map values to indices for last parameter
    # last can be any value in A or -1 (meaning -infinity)

    @lru_cache(maxsize=None)
    def wins(l, r, last):
        # True if current player wins from state (l, r, last)
        if l > r:
            return False
        results = []
        if A[l] > last:
            results.append(not wins(l+1, r, A[l]))
        if A[r] > last:
            results.append(not wins(l, r-1, A[r]))
        return any(results)

    print("Alice" if wins(0, n-1, -1) else "Bob")

solve()

